#include<bits/stdc++.h>
using namespace std;
const int V=1<<13;
int n,a[5010],b[5010];
long long dp[2][V+10];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d",&n);
        int max1=0;
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            max1=max(max1,a[i]);
        }
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&b[i]);
        }
        max1=(1<<(__lg(max1)+1));
        memset(dp,0x3f,sizeof(dp));
        dp[n&1][a[n]]=0;
        for(int i=n-1;i>=1;i--)
        {
            int now=(i&1),pre=((i&1)^1);
            memset(dp[now],0x3f,sizeof(dp[now]));
            long long min1=LLONG_MAX;
            for(int j=max1-1;j>=0;j--)
            {
                int k=a[i]^j^a[i+1];
                if(k<=j)
                {
                    dp[now][k]=min(dp[now][k],dp[pre][j]);
                }
                min1=min(min1,dp[pre][j]);
                dp[now][j]=min(dp[now][j],min1+b[i]);
            }
        }
        long long ans=LLONG_MAX;
        for(int i=0;i<max1;i++)
        {
            ans=min(ans,dp[1][i]);
            dp[n&1][i]=b[n];
        }
        for(int i=n-1;i>=1;i--)
        {
            int now=(i&1),pre=((i&1)^1);
            long long min1=LLONG_MAX;
            for(int j=0;j<max1;j++)
            {
                min1=min(min1,dp[pre][j]);
            }
            for(int j=0;j<max1;j++)
            {
                dp[now][j]=min1+b[i];
                if((a[i]^j)<=(a[i+1]^j))
                {
                    dp[now][j]=min(dp[now][j],dp[pre][j]);
                }
            }
        }
        for(int i=0;i<max1;i++)
        {
            ans=min(ans,dp[1][i]);
        }
        printf("%lld\n",ans);
    }
    return 0;
}
